/* Map a (bilingual) pricing feature line to the most relevant icon key.
   Order = specificity: the first matching rule wins. */
function pickKey(text: string): string {
  const t = text.toLowerCase();
  const has = (...kw: string[]) => kw.some((k) => t.includes(k));
  if (has("certificat", "sha-256", "deposit", "dépôt", "depot")) return "shield";
  if (has("wavematch", "stolen", "volé", "vole", "scanne", "scan")) return "soundwave";
  if (has("share link", "liens de partage", "trackable share", "partage track")) return "link";
  if (has("campaign", "campagne")) return "letter";
  if (has("storage", "stockage", " mb", " mo", " go")) return "database";
  if (has("profile", "profil", "bio")) return "user";
  if (has("theme", "thème", "thèmes")) return "gallery";
  if (has("everything in pro", "tout ce qui")) return "star";
  if (has("follow-up", "follow up", "relance")) return "bell";
  if (has("upload", "youtube", "téléversement")) return "upload";
  if (has("opportunit", "submission", "soumission")) return "sale";
  if (has("0% fee", "0% de frais")) return "moneybag";
  if (has("tracking", "suivi", "analytics", "ouvertures", "clics", "opens", "clicks")) return "graph";
  if (has("contact")) return "users";
  if (has("sell", "vends", "vente", "fee", "frais")) return "tag";
  return "check";
}

/** Contextual, themeable (currentColor) icon for one pricing feature row. */
export function PricingFeatureIcon({ text, className = "" }: { text: string; className?: string }) {
  const ic = ICONS[pickKey(text)] || ICONS.check;
  return (
    <svg
      viewBox={ic.v}
      fill="none"
      stroke="currentColor"
      strokeLinecap="round"
      strokeLinejoin="round"
      aria-hidden="true"
      className={className}
      dangerouslySetInnerHTML={{ __html: ic.p }}
    />
  );
}
